{
  "name": "Gemini Nexus",
  "description": "A unified interface for Google's Gemini 3 & 2.5 models, featuring Multimodal Chat, Real-time Live Audio, and Veo Video Generation.",
  "requestFramePermissions": [
    "microphone",
    "camera"
  ]
}

export enum View {
  Chat = 'Chat',
  Live = 'Live',
  Video = 'Video',
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string; // base64
  isError?: boolean;
}

export interface VideoGenerationState {
  isGenerating: boolean;
  videoUri?: string;
  error?: string;
}

// Window augmentation for Veo Key Selection
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
    webkitAudioContext: typeof AudioContext;
  }
}

// Models
export const MODEL_TEXT_CHAT = 'gemini-3-flash-preview';
export const MODEL_LIVE_AUDIO = 'gemini-2.5-flash-native-audio-preview-09-2025';
export const MODEL_VIDEO_VEO = 'veo-3.1-fast-generate-preview';

// Configs
export const AUDIO_SAMPLE_RATE_INPUT = 16000;
export const AUDIO_SAMPLE_RATE_OUTPUT = 24000;

import { Blob } from '@google/genai';

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export const convertBlobToBase64 = (blob: globalThis.Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { MODEL_TEXT_CHAT, MODEL_VIDEO_VEO } from "../constants";

// Helper to get client. We create a new instance when needed to ensure fresh keys if selected.
export const getClient = (): GoogleGenAI => {
  const apiKey = process.env.API_KEY || '';
  return new GoogleGenAI({ apiKey });
};

export const createChatSession = (systemInstruction?: string): Chat => {
  const ai = getClient();
  return ai.chats.create({
    model: MODEL_TEXT_CHAT,
    config: {
      systemInstruction,
    },
  });
};

export const generateVideo = async (prompt: string): Promise<string | null> => {
  // Ensure we have a fresh client (important for key selection in Veo)
  const ai = getClient();

  let operation = await ai.models.generateVideos({
    model: MODEL_VIDEO_VEO,
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9',
    },
  });

  // Poll for completion
  while (!operation.done) {
    await new Promise((resolve) => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!videoUri) return null;

  // Append key for download/playback
  return `${videoUri}&key=${process.env.API_KEY}`;
};

