import React, { useState, useRef, useEffect } from 'react';
import { Chat, GenerateContentResponse } from '@google/genai';
import { createChatSession, getClient } from '../services/geminiService';
import { Message } from '../types';
import { convertBlobToBase64 } from '../services/audioUtils';

const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'model', text: 'Hello! I am Gemini 3 Flash. How can I help you today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatSessionRef.current = createChatSession();
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleImageSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedImage(file);
      const base64 = await convertBlobToBase64(file);
      setImagePreview(`data:${file.type};base64,${base64}`);
    }
  };

  const clearImage = () => {
    setSelectedImage(null);
    setImagePreview(null);
  };

  const sendMessage = async () => {
    if ((!input.trim() && !selectedImage) || isLoading) return;

    const currentInput = input;
    const currentImage = selectedImage;
    const currentPreview = imagePreview;

    // Reset inputs immediately
    setInput('');
    clearImage();

    // Add user message to UI
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: currentInput,
      image: currentPreview || undefined,
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // If we have an image, we can't use the simple chat history easily in this demo structure 
      // without more complex state management, but Gemini API supports it.
      // For this demo, if image is present, we use generateContent on the model directly or 
      // handle it within chat if valid.
      // However, chat.sendMessageStream supports content parts.

      let stream;

      if (currentImage && currentPreview) {
          // If image is present, we must format the content parts
          const base64Data = currentPreview.split(',')[1];
          const parts = [
             { text: currentInput },
             { inlineData: { mimeType: currentImage.type, data: base64Data } }
          ];

          // Note: chat.sendMessageStream accepts a string message or parts.
          // Type definition in SDK might be strict, so we cast if needed or construct object properly.
          // SDK: chat.sendMessageStream({ message: ... }) 
          // The message property can be string or Part[]

          // Re-instantiate chat if needed or just send message
          if (!chatSessionRef.current) chatSessionRef.current = createChatSession();

          // @ts-ignore - The SDK types allow complex message structures but sometimes TS complains
          stream = await chatSessionRef.current.sendMessageStream({ 
            message: { parts } // Constructing content correctly
          });

      } else {
        if (!chatSessionRef.current) chatSessionRef.current = createChatSession();
        stream = await chatSessionRef.current.sendMessageStream({ message: currentInput });
      }

      // Add placeholder for model response
      const modelMsgId = (Date.now() + 1).toString();
      setMessages(prev => [...prev, { id: modelMsgId, role: 'model', text: '' }]);

      let fullText = '';

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        const text = c.text || '';
        fullText += text;

        setMessages(prev => prev.map(msg => 
          msg.id === modelMsgId ? { ...msg, text: fullText } : msg
        ));
      }

    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "Sorry, I encountered an error.", isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <div className="flex flex-col h-full bg-background text-gray-100">
      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`
              max-w-[85%] md:max-w-[70%] rounded-2xl px-4 py-3 shadow-md
              ${msg.role === 'user' 
                ? 'bg-primary text-white rounded-br-none' 
                : 'bg-surface text-gray-100 rounded-bl-none border border-gray-700'}
              ${msg.isError ? 'border-red-500 border bg-red-900/20' : ''}
            `}>
              {msg.image && (
                <img src={msg.image} alt="User upload" className="max-w-full h-auto rounded-lg mb-2 border border-white/20" />
              )}
              <div className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-surface border-t border-gray-700">
        {imagePreview && (
           <div className="mb-2 relative inline-block">
             <img src={imagePreview} alt="Preview" className="h-20 w-20 object-cover rounded-lg border border-gray-600" />
             <button 
                onClick={clearImage}
                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 w-6 h-6 flex items-center justify-center text-xs shadow-lg hover:bg-red-600"
             >
               ✕
             </button>
           </div>
        )}
        <div className="flex items-end gap-2 max-w-4xl mx-auto">
           <label className="cursor-pointer p-3 text-gray-400 hover:text-white transition-colors bg-gray-800 rounded-lg border border-gray-600 hover:border-gray-500">
             <input type="file" accept="image/*" className="hidden" onChange={handleImageSelect} />
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
           </label>

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your message..."
            className="flex-1 bg-gray-900 border border-gray-600 text-white rounded-lg p-3 max-h-32 resize-none focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent scrollbar-hide"
            rows={1}
            style={{ minHeight: '48px' }}
          />
          <button
            onClick={sendMessage}
            disabled={isLoading || (!input.trim() && !selectedImage)}
            className={`
              p-3 rounded-lg font-medium transition-all
              ${isLoading || (!input.trim() && !selectedImage)
                ? 'bg-gray-700 text-gray-500 cursor-not-allowed'
                : 'bg-primary hover:bg-primaryHover text-white shadow-lg shadow-indigo-500/20'}
            `}
          >
            {isLoading ? (
               <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
            )}
          </button>
        </div>
        <p className="text-center text-xs text-gray-500 mt-2">Gemini 3 Flash Preview</p>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { getClient } from '../services/geminiService';
import { createPcmBlob, decode, decodeAudioData, encode } from '../services/audioUtils';
import { AUDIO_SAMPLE_RATE_INPUT, AUDIO_SAMPLE_RATE_OUTPUT, MODEL_LIVE_AUDIO } from '../constants';

const LiveInterface: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [status, setStatus] = useState<'disconnected' | 'connecting' | 'connected' | 'error'>('disconnected');
  const [volume, setVolume] = useState(0);

  // Audio Context and Processing Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null); // To hold the live session
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  // Visualization canvas
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number>();

  useEffect(() => {
    return () => {
      disconnect();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const drawVisualizer = () => {
     // Simple fake visualizer for UI effect based on volume state
     if (!canvasRef.current) return;
     const ctx = canvasRef.current.getContext('2d');
     if (!ctx) return;

     const width = canvasRef.current.width;
     const height = canvasRef.current.height;

     ctx.clearRect(0, 0, width, height);
     ctx.fillStyle = '#6366f1'; // Primary color

     // Draw bars based on volume
     const bars = 20;
     const barWidth = width / bars;

     for(let i=0; i<bars; i++) {
        // Randomize slightly but base on volume
        const h = Math.random() * (volume * height * 2); 
        ctx.fillRect(i * barWidth, (height - h) / 2, barWidth - 2, h);
     }

     animationFrameRef.current = requestAnimationFrame(drawVisualizer);
  };

  useEffect(() => {
    if (isConnected) {
        drawVisualizer();
    } else {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    }
    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isConnected, volume]);


  const connect = async () => {
    try {
      setStatus('connecting');
      const ai = getClient();

      // Initialize Audio Contexts
      const AudioContextClass = window.AudioContext || window.webkitAudioContext;
      inputAudioContextRef.current = new AudioContextClass({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
      outputAudioContextRef.current = new AudioContextClass({ sampleRate: AUDIO_SAMPLE_RATE_OUTPUT });

      const outputNode = outputAudioContextRef.current.createGain();
      outputNode.connect(outputAudioContextRef.current.destination);

      // Get Mic Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: MODEL_LIVE_AUDIO,
        callbacks: {
          onopen: () => {
            console.log('Live Session Opened');
            setStatus('connected');
            setIsConnected(true);

            // Setup Input Processing
            if (!inputAudioContextRef.current) return;
            const source = inputAudioContextRef.current.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
              const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);

              // Calculate rough volume for visualizer
              let sum = 0;
              for(let i=0; i<inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContextRef.current.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
             const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
             if (base64Audio && outputAudioContextRef.current) {
                const ctx = outputAudioContextRef.current;

                // Ensure timing
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                try {
                  const audioBuffer = await decodeAudioData(
                    decode(base64Audio),
                    ctx,
                    AUDIO_SAMPLE_RATE_OUTPUT,
                    1
                  );

                  const source = ctx.createBufferSource();
                  source.buffer = audioBuffer;
                  source.connect(outputNode);

                  source.addEventListener('ended', () => {
                    sourcesRef.current.delete(source);
                  });

                  source.start(nextStartTimeRef.current);
                  nextStartTimeRef.current += audioBuffer.duration;
                  sourcesRef.current.add(source);

                } catch (e) {
                   console.error("Error decoding audio", e);
                }
             }

             if (message.serverContent?.interrupted) {
                 // Stop all current sources
                 sourcesRef.current.forEach(s => {
                    try { s.stop(); } catch(e) {}
                 });
                 sourcesRef.current.clear();
                 nextStartTimeRef.current = 0;
             }
          },
          onclose: () => {
            console.log('Session Closed');
            disconnect();
          },
          onerror: (e) => {
            console.error(e);
            setStatus('error');
            disconnect();
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            }
        }
      });

      sessionRef.current = sessionPromise;

    } catch (err) {
      console.error("Connection failed", err);
      setStatus('error');
      setIsConnected(false);
    }
  };

  const disconnect = () => {
    setIsConnected(false);
    setStatus('disconnected');

    // Stop tracks
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop());
      streamRef.current = null;
    }

    // Stop processor
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }

    // Close contexts
    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        inputAudioContextRef.current.close();
    }
    if (outputAudioContextRef.current && outputAudioContextRef.current.state !== 'closed') {
        outputAudioContextRef.current.close();
    }

    // Close session if possible
    // The SDK doesn't expose a clean sync .close() on the promise easily in the simplified type provided,
    // but usually session.close() is available on the resolved object.
    if (sessionRef.current) {
        sessionRef.current.then((s: any) => {
            if(s.close) s.close();
        });
        sessionRef.current = null;
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full bg-background p-6">
       <div className="max-w-md w-full bg-surface rounded-2xl p-8 border border-gray-700 shadow-2xl flex flex-col items-center text-center">
          <div className="mb-8 relative">
              <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 
                  ${status === 'connected' ? 'bg-primary/20 ring-4 ring-primary/40' : 'bg-gray-800'}`}>
                  {status === 'connected' ? (
                     <div className="text-4xl animate-pulse">🎙️</div>
                  ) : (
                     <div className="text-4xl text-gray-600">🔇</div>
                  )}
              </div>
              {status === 'connected' && (
                <div className="absolute inset-0 rounded-full animate-pulse-slow border-2 border-primary/30"></div>
              )}
          </div>

          <h2 className="text-2xl font-bold text-white mb-2">Gemini Live</h2>
          <p className="text-gray-400 mb-8">
            {status === 'disconnected' && "Ready to connect. Have a real-time conversation."}
            {status === 'connecting' && "Establishing connection..."}
            {status === 'connected' && "Listening... Speak naturally."}
            {status === 'error' && "Connection failed. Please check your API key and permissions."}
          </p>

          <canvas 
            ref={canvasRef} 
            width={300} 
            height={60} 
            className="mb-8 w-full h-[60px] rounded bg-gray-900/50"
          />

          <button
             onClick={isConnected ? disconnect : connect}
             disabled={status === 'connecting'}
             className={`
                px-8 py-3 rounded-full font-semibold text-lg transition-all transform hover:scale-105
                ${isConnected 
                    ? 'bg-red-500 hover:bg-red-600 text-white shadow-red-500/20 shadow-lg' 
                    : 'bg-primary hover:bg-primaryHover text-white shadow-indigo-500/20 shadow-lg'}
             `}
          >
             {isConnected ? 'End Session' : 'Start Conversation'}
          </button>
       </div>
    </div>
  );
};

export default LiveInterface;

import React, { useState } from 'react';
import { generateVideo } from '../services/geminiService';
import { VideoGenerationState } from '../types';

const VideoInterface: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [state, setState] = useState<VideoGenerationState>({ isGenerating: false });

  // Handle Key Selection for Veo
  const ensureApiKey = async (): Promise<boolean> => {
    if (!window.aistudio) return false;
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
        // Assume success as per instructions
        return true;
      }
      return true;
    } catch (e) {
      console.error("Error checking API key", e);
      return false;
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    const keyReady = await ensureApiKey();
    if (!keyReady) {
        setState({ isGenerating: false, error: 'API Key selection failed or cancelled.' });
        return;
    }

    setState({ isGenerating: true, error: undefined });

    try {
      const videoUri = await generateVideo(prompt);
      if (videoUri) {
        setState({ isGenerating: false, videoUri });
      } else {
        setState({ isGenerating: false, error: 'Failed to generate video.' });
      }
    } catch (err: any) {
        let msg = 'An unexpected error occurred.';
        if (err.message && err.message.includes("Requested entity was not found")) {
            // As per instructions, reset key state if this specific error occurs
             if (window.aistudio) {
                try { await window.aistudio.openSelectKey(); } catch(e) {}
             }
             msg = "Entity not found. Please try selecting your API key again.";
        } else {
            msg = err.message || msg;
        }
        setState({ isGenerating: false, error: msg });
    }
  };

  return (
    <div className="flex flex-col items-center p-6 h-full bg-background overflow-y-auto">
      <div className="w-full max-w-2xl space-y-8">
         <div className="text-center">
            <h2 className="text-3xl font-bold bg-gradient-to-r from-purple-400 to-pink-600 bg-clip-text text-transparent mb-2">
                Veo Video Generator
            </h2>
            <p className="text-gray-400">Generate 720p videos from text prompts.</p>
         </div>

         <div className="bg-surface p-6 rounded-2xl border border-gray-700 shadow-xl">
            <label className="block text-sm font-medium text-gray-300 mb-2">Prompt</label>
            <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="A neon hologram of a cat driving at top speed..."
                className="w-full h-32 bg-gray-900 border border-gray-600 rounded-lg p-4 text-white focus:ring-2 focus:ring-purple-500 focus:border-transparent resize-none mb-4"
            />

            <button
                onClick={handleGenerate}
                disabled={state.isGenerating || !prompt.trim()}
                className={`w-full py-3 rounded-lg font-bold text-lg transition-all
                   ${state.isGenerating 
                     ? 'bg-gray-700 text-gray-400 cursor-not-allowed' 
                     : 'bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-500 hover:to-pink-500 text-white shadow-lg'}
                `}
            >
                {state.isGenerating ? (
                    <span className="flex items-center justify-center gap-2">
                        <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                        Generating (this may take a minute)...
                    </span>
                ) : 'Generate Video'}
            </button>

            {state.error && (
                <div className="mt-4 p-4 bg-red-900/30 border border-red-500/50 rounded-lg text-red-200 text-sm">
                    {state.error}
                </div>
            )}
         </div>

         {state.videoUri && (
             <div className="bg-surface p-6 rounded-2xl border border-gray-700 shadow-xl animate-fade-in">
                 <h3 className="text-lg font-semibold text-white mb-4">Result</h3>
                 <div className="aspect-video bg-black rounded-lg overflow-hidden relative">
                    <video 
                        controls 
                        autoPlay 
                        loop 
                        className="w-full h-full object-contain"
                        src={state.videoUri}
                    />
                 </div>
                 <div className="mt-4 flex justify-end">
                    <a href={state.videoUri} download className="text-sm text-purple-400 hover:text-purple-300">
                        Download Video
                    </a>
                 </div>
             </div>
         )}
      </div>

      <div className="mt-8 text-center text-xs text-gray-500 max-w-md">
          Note: This feature uses Veo models which require a paid billing project. 
          See <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="underline hover:text-gray-300">billing documentation</a>.
      </div>
    </div>
  );
};

