  onLocationClick: () => void;
  onMapClick: () => void;
  onOwnerClick: () => void;
}

const RedMapPinIcon = ({ className = "w-10 h-10" }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
