                              type="time" 
                              value={openingTime} 
                              onChange={e => setOpeningTime(e.target.value)} 
                              className="w-full bg-[#f8fafc] border border-gray-200 rounded-2xl py-4 px-6 text-sm font-black text-black outline-none focus:ring-2 focus:ring-[#a82283]/10" 
                          />
                      </div>
                      <div className="flex-1">
                          <label className="text-[10px] font-bold text-gray-400 mb-1.5 block ml-1">CLOSING TIME</label>
                          <input 
                              type="time" 
                              value={closingTime} 
                              onChange={e => setClosingTime(e.target.value)} 
                              className="w-full bg-[#f8fafc] border border-gray-200 rounded-2xl py-4 px-6 text-sm font-black text-black outline-none focus:ring-2 focus:ring-[#a82283]/10" 
                          />
                      </div>
                  </div>

                  <input 
                    type="tel" 
                    placeholder="Phone Number (Optional)" 
                    value={shopPhone} 
                    onChange={e => setShopPhone(e.target.value)} 
                    className="w-full bg-[#f8fafc] border border-gray-200 rounded-2xl py-4 px-6 text-sm font-black text-black outline-none focus:ring-2 focus:ring-[#a82283]/10 mb-4" 
                  />
                </section>

                <section>
                    <label className="text-[11px] font-black text-black uppercase tracking-[0.2em] mb-4 block">BUSINESS INFO</label>

                    <div className="relative mb-4">
                        <CreditCard className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                        <input 
                            type="text" 
                            placeholder="GST Number" 
                            value={gstNumber} 
                            onChange={e => setGstNumber(e.target.value)} 
                            className="w-full bg-[#f8fafc] border border-gray-200 rounded-2xl py-4 pl-14 pr-6 text-sm font-black text-black outline-none focus:ring-2 focus:ring-[#a82283]/10" 
                        />
                    </div>

                    <div className="relative">
                        <Building2 className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                        <input 
                            type="text" 
                            placeholder="Bank Info (Account No, IFSC, Branch Name)" 
                            value={bankInfo} 
                            onChange={e => setBankInfo(e.target.value)} 
                            className="w-full bg-[#f8fafc] border border-gray-200 rounded-2xl py-4 pl-14 pr-6 text-sm font-black text-black outline-none focus:ring-2 focus:ring-[#a82283]/10" 
                        />
                    </div>
                </section>

                <section>
                    <label className="text-[11px] font-black text-black uppercase tracking-[0.2em] mb-4 block">LOCATION</label>
                    <div className="flex gap-4">
                        <button 
                            type="button" 
                            onClick={handleGetCurrentLocation} 
                            disabled={isLocating}
                            className={`flex-1 font-black text-xs py-4 rounded-2xl flex items-center justify-center gap-2 transition-all disabled:opacity-70 border ${
                                shopLat && shopLng ? 'bg-green-50 text-green-700 border-green-100' : 'bg-[#fdf0f8] text-[#a82283] border-transparent hover:bg-[#fae3f1]'
                            }`}
                        >
                            {isLocating ? <Loader2 className="w-4 h-4 animate-spin" /> : (shopLat && shopLng ? <CheckCircle className="w-4 h-4" /> : <Send className="w-4 h-4 rotate-[-45deg]" />)}
                            {isLocating ? 'Locating...' : (shopLat && shopLng ? 'Location Set' : 'Locate Me')}
                        </button>
                        <button type="button" onClick={() => setShowMapPicker(true)} className="flex-[0.6] bg-white border border-gray-200 text-black font-black text-xs py-4 rounded-2xl flex items-center justify-center gap-2 hover:bg-gray-50 transition-all shadow-sm">
                            <MapIcon className="w-4 h-4" /> Map Pin
                        </button>
                    </div>
                    {(shopLat && shopLng) && (
                        <div className="mt-2 flex items-center gap-2 text-[10px] text-green-600 font-bold bg-green-50 px-3 py-1.5 rounded-lg w-fit">
                            <MapPin className="w-3 h-3" /> 
                            {shopAddress ? shopAddress : `Location set: ${shopLat.toFixed(4)}, ${shopLng.toFixed(4)}`}
                        </div>
                    )}
                </section>
                <button 
                    type="submit" 
                    disabled={isSubmitting}
                    className="w-full bg-[#a82283] text-white font-black py-5 rounded-[1.5rem] text-base shadow-xl active:scale-[0.98] transition-all mt-4 disabled:opacity-70 disabled:scale-100 flex items-center justify-center gap-2"
                >
                    {isSubmitting ? (
                        <>
                            <Loader2 className="w-5 h-5 animate-spin" /> Creating...
                        </>
                    ) : (
                        'Create Shop Profile'
                    )}
                </button>
              </form>
            </div>
          </div>
        )}

        {view === 'add-item' && (
           <SmartLister 
              shopId={selectedShop?.id} 
              onClose={() => setView(selectedShop ? 'shop-details' : 'list')}
              onSuccess={handleSmartListerSuccess}
           />
        )}
      </main>

      {showMapPicker && (
         <ShopMapPicker 
            initialLat={shopLat || 26.2183} 
            initialLng={shopLng || 78.1828} 
            initialSearch={shopAddress}
            onClose={() => setShowMapPicker(false)}
            onConfirm={(lat, lng, address) => {
                setShopLat(lat);
                setShopLng(lng);
                if(address) setShopAddress(address);
                setShowMapPicker(false);
            }}
         />
      )}

      {showWebcam && (
          <WebcamCapture 
            onCapture={handleShopImageFile}
            onClose={() => setShowWebcam(false)} 
          />
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { UserRole, User } from '../types';
import { loginUser, registerUser } from '../utils';

interface AuthProps {
  onLogin: (user: User) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>('user');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
        if (isLogin) {
          const user = await loginUser(email, password);
          if (user) {
            onLogin(user);
          } else {
            setError('Invalid email or password.');
          }
        } else {
          const newUser = { id: Date.now().toString(), name, email, password, role: 'user' as UserRole };
          if (await registerUser(newUser)) {
            onLogin(newUser);
          } else {
            setError('User already exists.');
          }
        }
    } catch(e) {
        setError("An error occurred. Please try again.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setIsLoading(true);
    setTimeout(async () => {
        const googleEmail = "alex.doe@gmail.com";
        const googlePassword = "google_auth_token_simulated"; 

        const existingUser = await loginUser(googleEmail, googlePassword);

        if (existingUser) {
            onLogin(existingUser);
        } else {
            const newUser: User = {
                id: 'google_' + Date.now(),
                name: "Alex Doe",
                email: googleEmail,
                password: googlePassword,
                role: 'user',
            };
            await registerUser(newUser);
            onLogin(newUser);
        }
        setIsLoading(false);
    }, 800);
  };

  return (
    <div className="min-h-screen bg-white flex flex-col justify-center px-6 py-12 lg:px-8 font-sans">
      <div className="sm:mx-auto sm:w-full sm:max-w-sm flex flex-col items-center">
        {/* Logo Section */}
        <div className="flex items-center gap-2.5 mb-6">
            <div className="w-10 h-10 shrink-0">
                <svg viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-full h-full drop-shadow-sm">
                    {/* Handle - Rounded arch on top */}
                    <path d="M 32 28 C 32 10 68 10 68 28" stroke="#F97316" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round" />

                    {/* Bag Body Left - with gap at bottom */}
                    <path d="M 32 28 H 20 A 8 8 0 0 0 12 36 V 82 A 8 8 0 0 0 20 90 H 38" stroke="#F97316" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round" />

                    {/* Bag Body Right - with gap at bottom */}
                    <path d="M 68 28 H 80 A 8 8 0 0 1 88 36 V 82 A 8 8 0 0 1 80 90 H 62" stroke="#F97316" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round" />

                    {/* Location Pin - Centered inside */}
                    <path d="M 50 80 C 50 80 62 66 62 55 A 12 12 0 1 0 38 55 C 38 66 50 80 50 80 Z" stroke="#F97316" strokeWidth="7" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
            </div>
            <div className="flex items-baseline leading-none">
                <span className="text-3xl font-black text-[#F97316] tracking-tighter" style={{ fontFamily: 'Inter, sans-serif' }}>Shop</span>
                <span className="text-3xl font-black text-[#0f172a] tracking-tighter" style={{ fontFamily: 'Inter, sans-serif' }}>ioo</span>
            </div>
        </div>

        <p className="text-center text-sm font-medium text-gray-500 mt-2">
          {isLogin ? 'Sign in to your account' : 'Create a new account'}
        </p>
      </div>

      <div className="mt-10 sm:mx-auto sm:w-full sm:max-w-sm">
        <form className="space-y-5" onSubmit={handleSubmit}>
          {!isLogin && (
             <div>
               <label className="block text-xs font-bold text-gray-900 mb-1 ml-1">Full Name</label>
               <input type="text" required value={name} onChange={e => setName(e.target.value)} className="block w-full rounded-xl border-0 py-3 text-gray-900 shadow-sm ring-1 ring-inset ring-gray-200 placeholder:text-gray-400 focus:ring-2 focus:ring-inset focus:ring-[#a82283] sm:text-sm sm:leading-6 px-4 bg-gray-50" />
             </div>
          )}

          <div>
            <label className="block text-xs font-bold text-gray-900 mb-1 ml-1">Email address</label>
            <input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="block w-full rounded-xl border-0 py-3 text-gray-900 shadow-sm ring-1 ring-inset ring-gray-200 placeholder:text-gray-400 focus:ring-2 focus:ring-inset focus:ring-[#a82283] sm:text-sm sm:leading-6 px-4 bg-gray-50" />
          </div>

          <div>
            <div className="flex items-center justify-between">
              <label className="block text-xs font-bold text-gray-900 mb-1 ml-1">Password</label>
            </div>
            <input type="password" required value={password} onChange={e => setPassword(e.target.value)} className="block w-full rounded-xl border-0 py-3 text-gray-900 shadow-sm ring-1 ring-inset ring-gray-200 placeholder:text-gray-400 focus:ring-2 focus:ring-inset focus:ring-[#a82283] sm:text-sm sm:leading-6 px-4 bg-gray-50" />
          </div>

          {error && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-2 rounded-lg">{error}</p>}

          <div>
            <button type="submit" disabled={isLoading} className="flex w-full justify-center rounded-full bg-[#a82283] px-3 py-3 text-sm font-bold leading-6 text-white shadow-lg hover:bg-[#8a1c6b] active:scale-95 transition-all focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#a82283] disabled:opacity-70">
              {isLoading ? 'Processing...' : (isLogin ? 'Sign in' : 'Register')}
            </button>
          </div>
        </form>

