            iconSize: [24, 34],
            iconAnchor: [12, 34],
            popupAnchor: [0, -34]
        });

        const marker = L.marker([initialLat, initialLng], { draggable: true, icon: userIcon }).addTo(map);

        marker.on('dragend', () => {
             setSelectedMapShop(null);
             if (routeLineRef.current) routeLineRef.current.remove();
