        mapRef.current = map; 
        userMarkerRef.current = marker;
    }

    if (showMap && mapRef.current) {
        shopMarkersRef.current.forEach(m => m.remove());
        shopMarkersRef.current = [];

        const shopsToDisplay = activeMapCategory 
